import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface KPI {
  name: string;
  value: number;
  unit: string;
  change: number;
  changeDirection: string;
}

interface ChartData {
  barData: { category: string; value: number }[];
}

interface ResponseData {
  KPIs: KPI[];
  chartData: ChartData;
}

export default function Widget() {
  const data = response.data as ResponseData;
  const { KPIs } = data;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFF8E1' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          {KPIs.slice(0, 3).map((kpi) => (
            <Box key={kpi.name}>
              <Stack direction="row" justifyContent="space-between" alignItems="center">
                <Typography variant="body2" color="text.secondary">
                  {kpi.name}
                </Typography>
                <Stack direction="row" alignItems="center" spacing={0.5}>
                  <Typography variant="body1" fontWeight={600} sx={{ color: '#FF5722' }}>
                    {kpi.value.toLocaleString()} {kpi.unit}
                  </Typography>
                  <Chip
                    icon={kpi.changeDirection === 'up' ? <TrendingUp sx={{ fontSize: 16 }} /> : <TrendingDown sx={{ fontSize: 16 }} />}
                    label={`${kpi.change}%`}
                    sx={{
                      bgcolor: kpi.changeDirection === 'up' ? '#4CAF50' : '#F44336',
                      color: 'white',
                      fontSize: 10,
                    }}
                  />
                </Stack>
              </Stack>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
